param(
  [string]$ProjectRoot = "F:\1_A_Disk_D\Tool\mcp-plan",
  [switch]$CommitAndPush
)

$ErrorActionPreference = "Stop"

function Fail($message) {
  Write-Host ""
  Write-Host "ERROR: $message" -ForegroundColor Red
  exit 1
}

if (-not (Test-Path $ProjectRoot)) {
  Fail "Project root not found: $ProjectRoot"
}

Set-Location $ProjectRoot

$backendPath = Join-Path $ProjectRoot "apps\backend\server.js"
$pagePath = Join-Path $ProjectRoot "src\app\mcp\settings\page.tsx"
$migrationPath = Join-Path $ProjectRoot "supabase\migrations\20260705_mcp_route_session_status_contract.sql"

if (-not (Test-Path $backendPath)) { Fail "Backend file not found: $backendPath" }
if (-not (Test-Path $pagePath)) { Fail "Settings page not found: $pagePath" }

$backupDir = Join-Path $env:TEMP ("mcp-route-session-status-backup-" + (Get-Date -Format "yyyyMMdd-HHmmss"))
New-Item -ItemType Directory -Path $backupDir | Out-Null
Copy-Item $backendPath (Join-Path $backupDir "server.js.bak")
Copy-Item $pagePath (Join-Path $backupDir "page.tsx.bak")
Write-Host "Backup outside repo: $backupDir" -ForegroundColor Cyan

[System.IO.File]::WriteAllBytes($migrationPath, [Convert]::FromBase64String(""))
Write-Host "Wrote migration file" -ForegroundColor Green

$backend = [System.IO.File]::ReadAllText($backendPath, [System.Text.Encoding]::UTF8)
$helpers = [System.Text.Encoding]::UTF8.GetString([Convert]::FromBase64String(""))

if ($backend -notmatch "function normalizeMcpRouteSessionStatus") {
  $anchor = "`nfunction randomId(prefix)"
  $index = $backend.IndexOf($anchor)
  if ($index -lt 0) { Fail "Anchor function randomId(prefix) not found" }
  $backend = $backend.Substring(0, $index) + "`n" + $helpers + $backend.Substring($index)
  Write-Host "Inserted backend session-status helpers" -ForegroundColor Green
} else {
  Write-Host "Backend session-status helpers already exist" -ForegroundColor Yellow
}

$getRoute = 'if (url.pathname === "/api/mcp-settings/session-status") return wrap(await loadMcpRouteSessionStatusSettings(url));'
if (-not $backend.Contains($getRoute)) {
  $getAnchor = 'if (url.pathname === "/api/mcp-settings/customer-add-rule") return wrap(await loadMcpCustomerAddRuleSettings(url));'
  if (-not $backend.Contains($getAnchor)) {
    $getAnchor = 'if (url.pathname === "/api/mcp-settings/skip-reason-template") return wrap(await loadMcpSkipReasonTemplateSettings(url));'
  }
  if (-not $backend.Contains($getAnchor)) { Fail "GET route anchor not found" }
  $backend = $backend.Replace($getAnchor, $getAnchor + "`n  " + $getRoute)
  Write-Host "Inserted GET /api/mcp-settings/session-status" -ForegroundColor Green
} else {
  Write-Host "GET session-status route already exists" -ForegroundColor Yellow
}

$postRoute = 'if (url.pathname === "/api/mcp-settings/session-status") return wrap(await saveMcpRouteSessionStatusSettings(await readJsonBody(req)));'
if (-not $backend.Contains($postRoute)) {
  $postAnchor = 'if (url.pathname === "/api/mcp-settings/customer-add-rule") return wrap(await saveMcpCustomerAddRuleSettings(await readJsonBody(req)));'
  if (-not $backend.Contains($postAnchor)) {
    $postAnchor = 'if (url.pathname === "/api/mcp-settings/skip-reason-template") return wrap(await saveMcpSkipReasonTemplateSettings(await readJsonBody(req)));'
  }
  if (-not $backend.Contains($postAnchor)) { Fail "POST route anchor not found" }
  $backend = $backend.Replace($postAnchor, $postAnchor + "`n  " + $postRoute)
  Write-Host "Inserted POST /api/mcp-settings/session-status" -ForegroundColor Green
} else {
  Write-Host "POST session-status route already exists" -ForegroundColor Yellow
}

$utf8NoBom = New-Object System.Text.UTF8Encoding($false)
[System.IO.File]::WriteAllText($backendPath, $backend, $utf8NoBom)

[System.IO.File]::WriteAllBytes($pagePath, [Convert]::FromBase64String(""))
Write-Host "Wrote settings page from UTF-8 base64 payload" -ForegroundColor Green

Write-Host ""
Write-Host "Building..." -ForegroundColor Cyan
npm run build
if ($LASTEXITCODE -ne 0) {
  Fail "Build failed. Do not commit/push. Send full build log."
}

Write-Host ""
Write-Host "BUILD OK" -ForegroundColor Green

if ($CommitAndPush) {
  Write-Host ""
  Write-Host "Committing and pushing..." -ForegroundColor Cyan
  git add apps/backend/server.js src/app/mcp/settings/page.tsx supabase/migrations/20260705_mcp_route_session_status_contract.sql
  git commit -m "feat: add route session status settings"
  if ($LASTEXITCODE -ne 0) { Fail "git commit failed. Send git status --short." }
  git push origin main
  if ($LASTEXITCODE -ne 0) { Fail "git push failed. Send log." }
  Write-Host ""
  Write-Host "PUSH DONE. Run pullmcp on VPS after this." -ForegroundColor Green
} else {
  Write-Host ""
  Write-Host "Not committed yet. To commit and push automatically, run:" -ForegroundColor Yellow
  Write-Host 'powershell -ExecutionPolicy Bypass -File .\patch-mcp-route-session-status.ps1 -CommitAndPush' -ForegroundColor Yellow
}
